mapper.insert:
INSERT INTO sys_outbox_event (
    id, aggregate_type, aggregate_id, event_type, payload,
    status, retry_count, max_retry, next_retry_time,
    tenant_id, created_by, created_time, updated_by, updated_time, deleted, version
) VALUES (
    #{id}, #{aggregateType}, #{aggregateId}, #{eventType}, #{payload}::jsonb,
    #{status}, #{retryCount}, #{maxRetry}, #{nextRetryTime},
    #{tenantId}, #{createdBy}, #{createdTime}, #{updatedBy}, #{updatedTime}, #{deleted}, #{version}
)

mapper.select:
SELECT * FROM sys_outbox_event
WHERE id = #{id}
  AND deleted = FALSE

SELECT * FROM sys_outbox_event
WHERE status = 'PENDING'
  AND next_retry_time <= #{now}
  AND deleted = FALSE
ORDER BY created_time ASC
LIMIT #{batchSize}

mapper.delete:
DELETE FROM sys_outbox_event
WHERE status = 'SENT'
  AND created_time < #{before}
